import React, { useState, useEffect } from "react";
import { useNavigate, useParams } from "react-router-dom";

const AppraisalForm = () => {
  const navigate = useNavigate();
  const { id } = useParams();          // <-- detects edit mode

  const [formData, setFormData] = useState({
    employeeName: "",
    department: "",
    period: "",
    rating: "",
    status: "Pending",
  });

  // Load existing data if EDIT MODE
  useEffect(() => {
    if (!id) return;  // add page → ignore

    const stored = JSON.parse(localStorage.getItem("appraisals")) || [];
    const record = stored.find(a => String(a.id) === String(id));

    if (record) {
      setFormData(record);
    }

  }, [id]);

  // Handle input change
  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  // Handle Save
  const handleSubmit = (e) => {
    e.preventDefault();

    const existing = JSON.parse(localStorage.getItem("appraisals")) || [];

    // 🔹 EDIT MODE → Update existing
    if (id) {
      const updated = existing.map(a =>
        String(a.id) === String(id)
          ? { ...a, ...formData }
          : a
      );

      localStorage.setItem("appraisals", JSON.stringify(updated));
      alert("Appraisal Updated Successfully");
    }

    // 🔹 ADD MODE → Create new record
    else {
      const newRecord = {
        id: Date.now(),
        ...formData
      };

      existing.push(newRecord);
      localStorage.setItem("appraisals", JSON.stringify(existing));
      alert("Appraisal Added Successfully");
    }

    navigate("/dashboard/appraisal");
  };

  return (
    <div style={{ padding: "25px" }}>
      <h2>{id ? "Edit Employee Appraisal" : "Add Employee Appraisal"}</h2>

      <form onSubmit={handleSubmit} style={{ marginTop: "20px", maxWidth: "500px" }}>

        <label>Employee Name</label>
        <input
          name="employeeName"
          value={formData.employeeName}
          onChange={handleChange}
          required
        />

        <label>Department</label>
        <input
          name="department"
          value={formData.department}
          onChange={handleChange}
          required
        />

        <label>Review Period</label>
        <input
          name="period"
          value={formData.period}
          onChange={handleChange}
          required
        />

        <label>Rating</label>
        <input
          type="number"
          step="0.1"
          name="rating"
          value={formData.rating}
          onChange={handleChange}
          required
        />

        <label>Status</label>
        <select
          name="status"
          value={formData.status}
          onChange={handleChange}
        >
          <option>Pending</option>
          <option>Approved</option>
          <option>Rejected</option>
        </select>

        <br /><br />

        <button type="submit">
          {id ? "Update" : "Save"}
        </button>

        <button
          type="button"
          style={{ marginLeft: "10px" }}
          onClick={() => navigate("/dashboard/appraisal")}
        >
          Cancel
        </button>

      </form>
    </div>
  );
};

export default AppraisalForm;
